full_refresh.code:
// 1. 初始化硬件
DEV_Module_Init();

// 2. 初始化屏幕（全刷新模式）
EPD_10in85_Init();

// 3. 分配帧缓冲区
UBYTE *frame = (UBYTE *)malloc(680 * 480 / 8);

// 4. 创建画布
Paint_NewImage(frame, 680, 480, ROTATE_0, WHITE);
Paint_SelectImage(frame);
Paint_Clear(WHITE);

// 5. 绘制内容
Paint_DrawString_EN(50, 50, "Hello EPD!", &Font24, BLACK, WHITE);
Paint_DrawCircle(340, 240, 100, BLACK, DOT_PIXEL_2X2, DRAW_FILL_EMPTY);

// 6. 刷屏显示
EPD_10in85_Display(frame);

// 7. 睡眠
EPD_10in85_Sleep();

// 8. 释放资源
free(frame);
DEV_Module_Exit();

partial_refresh.code:
// 1. 硬件初始化 + 全刷新初始化
DEV_Module_Init();
EPD_10in85_Init();

// 2. 全屏刷一次内容
Paint_NewImage(frame, 680, 480, ROTATE_0, WHITE);
Paint_Clear(WHITE);
Paint_DrawString_EN(10, 10, "Static Header", &Font16, BLACK, WHITE);
EPD_10in85_Display(frame);

// 3. 局部刷新初始化
EPD_10in85_Init_Part();

// 4. 只更新小区域
Paint_ClearWindows(10, 100, 200, 150, WHITE);
Paint_DrawString_EN(10, 100, "Updated Content", &Font16, BLACK, WHITE);
EPD_10in85_DisplayPart(frame, 10, 100, 200, 50);

// 或使用区域刷新
EPD_10in85b_Display_Partial(frame, 10, 100, 200, 150);
